      'mdtldr search -H "API.*"                # Regex on headings only',
      'mdtldr search --mode structural "auth"  # Force structural mode',
      'mdtldr search --mode semantic "auth"    # Force semantic mode',
      'mdtldr search -n 5 "setup"              # Limit to 5 results',
