          `Creating semantic index (~${estimate.estimatedTimeSeconds}s, ~$${estimate.totalCost.toFixed(4)})...`,
        )
      }

      const result = yield* buildEmbeddings(resolvedDir, {
        force: false,
        onFileProgress: (progress) => {
          if (!json) {
            process.stdout.write(
