      Args.withDescription('Directory to search in'),
      Args.withDefault('.'),
    ),
    keyword: Options.boolean('keyword').pipe(
      Options.withAlias('k'),
      Options.withDescription('Force keyword search (content text match)'),
      Options.withDefault(false),
    ),
