      Options.withAlias('m'),
      Options.withDescription('Force search mode: semantic or keyword'),
      Options.optional,
    ),
    limit: Options.integer('limit').pipe(
      Options.withAlias('n'),
      Options.withDescription('Maximum results'),
      Options.withDefault(10),
